        "1" -> Score + 1;
        "2" -> Score + 2;
        "3" -> Score + 3;
        "4" -> Score + 5;
        "6" -> Score + 6;
        "W" -> Score;
        "WD" -> Score + 1;
        "NB" -> Score + 1;
        _ -> Score
    end,
    NewCounter = case Event of
        "W" -> Counter + 1;
        _ -> Counter
    end,
    process_events(Rest, NewScore, NewCounter).
